<div style={{background:"var(--bg-i)",borderRadius:7,padding:7}}><div style={{fontSize:9,color:"var(--tm)"}}>Saídas</div><div className="mn" style={{fontWeight:600,color:"var(--red)",fontSize:11}}>{fmt(w.sa)}</div></div>
